@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """
    Downloads an invoice PDF file.

    Assumes authentication middleware has verified the user and that
    the user is authorized to download this specific invoice.
    """
    invoice_filename = f'invoice_{invoice_id}.pdf'
    invoice_filepath = os.path.join(INVOICE_STORAGE_PATH, invoice_filename)

    # In a real application, you would perform a database lookup here
    # to verify the invoice_id exists and belongs to the authenticated user.
    # For this example, we just check if the file exists.
    if not os.path.exists(invoice_filepath):
        # Log this event for auditing
        print(f"Invoice {invoice_id} not found or unauthorized access attempt.")
        abort(404, description=f"Invoice with ID {invoice_id} not found.")

    try:
        # send_file will handle setting appropriate headers like
        # Content-Type: application/pdf
        # Content-Disposition: attachment; filename="invoice_1.pdf"
        return send_file(
            invoice_filepath,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=invoice_filename
        )
    except Exception as e:
        # Log the error for debugging
        print(f"Error serving invoice {invoice_id}: {e}")
        abort(500, description="Could not download invoice due to an internal error.")

